+// cloneLoopSpec creates a deep copy of a LoopSpec (gt-zn35j).
+func cloneLoopSpec(loop *LoopSpec) *LoopSpec {
+	if loop == nil {
+		return nil
+	}
+	clone := &LoopSpec{
+		Count: loop.Count,
+		Until: loop.Until,
+		Max:   loop.Max,
+	}
+	if len(loop.Body) > 0 {
+		clone.Body = make([]*Step, len(loop.Body))
+		for i, step := range loop.Body {
+			clone.Body[i] = cloneStepDeep(step)
+		}
+	}
+	return clone
+}

